3131	\begin{lemma}[Pullback of sheaves of modules along a morphism of schemes]
3132	  \label{lem:modules_pullback_mathlib}
3133	  \lean{AlgebraicGeometry.Scheme.Modules.pullback}
3134	  \mathlibok
3135	  \textit{Provided by Mathlib (\texttt{Mathlib.AlgebraicGeometry.Modules.Sheaf}).}
3136	  For a morphism of schemes \(f : X \to Y\), Mathlib supplies the pullback functor
3137	  \(f^{*} : Y.\mathrm{Modules} \to X.\mathrm{Modules}\) on sheaves of modules, left adjoint to
3138	  pushforward, hence colimit-preserving, and carrying the unit sheaf to the unit sheaf. The project
3139	  already uses this functor in the definition of local freeness. It is the geometric restriction
3140	  through which a presentation is transported to an open subscheme.
3141	\end{lemma}
3142	
3143	\begin{lemma}[Restriction of sheaves of modules along an open immersion]
3144	  \label{lem:modules_restrictFunctor_mathlib}
3145	  \lean{AlgebraicGeometry.Scheme.Modules.restrictFunctor}
3146	  \mathlibok
3147	  \textit{Provided by Mathlib (\texttt{Mathlib.AlgebraicGeometry.Modules.Sheaf}).}
3148	  For an open immersion \(f : X \to Y\), Mathlib supplies the restriction functor
3149	  \(f^{\mathrm{res}} : Y.\mathrm{Modules} \to X.\mathrm{Modules}\), with
3150	  \(\Gamma(f^{\mathrm{res}} M, U) = \Gamma(M, f(U))\) definitionally; it is a left adjoint (colimit
3151	  preserving) and carries the unit sheaf to the unit sheaf. This is the geometric
3152	  ``restrict to open \(U\)'' functor on \((\Spec R).\mathrm{Modules}\).
3153	\end{lemma}
3154	
3155	\begin{lemma}[Restriction is isomorphic to pullback]
3156	  \label{lem:modules_restrictFunctorIsoPullback_mathlib}
3157	  \lean{AlgebraicGeometry.Scheme.Modules.restrictFunctorIsoPullback}
3158	  \mathlibok
3159	  \textit{Provided by Mathlib (\texttt{Mathlib.AlgebraicGeometry.Modules.Sheaf}).}
3160	  For an open immersion \(f\), the restriction functor (\cref{lem:modules_restrictFunctor_mathlib})
3161	  is naturally isomorphic to the pullback functor (\cref{lem:modules_pullback_mathlib}):
3162	  \(f^{\mathrm{res}} \cong f^{*}\). This identifies the restriction functor with the
3163	  universal-property pullback, so a presentation transported along one transports along the other.
3164	\end{lemma}
3165	
3166	\begin{lemma}[Transport of a presentation along a colimit-preserving functor]
3167	  \label{lem:presentation_map_mathlib}
3168	  \lean{SheafOfModules.Presentation.map}
3169	  \mathlibok
3170	  \textit{Provided by Mathlib (\texttt{Mathlib.Algebra.Category.ModuleCat.Sheaf.Quasicoherent}).}
3171	  Let \(F\) be a functor between categories of sheaves of modules that preserves colimits and is
3172	  equipped with an isomorphism \(\eta : F(\mathrm{unit}_R) \cong \mathrm{unit}_S\) sending the unit
3173	  sheaf to the unit sheaf. Then any presentation \(P : \mathrm{Presentation}\,M\) (a
3174	  cokernel-of-free-modules description) induces a presentation
3175	  \(P.\mathrm{map}\,F\,\eta : \mathrm{Presentation}\,(F(M))\) of the image. Applied to the pullback
3176	  and restriction functors (\cref{lem:modules_pullback_mathlib},
3177	  \cref{lem:modules_restrictFunctor_mathlib}), it is how a presentation of \(M\) over one site is
3178	  carried to a presentation over another.
3179	\end{lemma}
