3196	\begin{lemma}[A presentation makes a sheaf of modules quasi-coherent]
3197	  \label{lem:presentation_isQuasicoherent_mathlib}
3198	  \lean{SheafOfModules.Presentation.isQuasicoherent}
3199	  \mathlibok
3200	  \textit{Provided by Mathlib
3201	  (\texttt{Mathlib.Algebra.Category.ModuleCat.Sheaf.Quasicoherent}).}
3202	  If a sheaf of \(R\)-modules \(M\) admits a presentation
3203	  \(P : \mathrm{Presentation}\,M\), then \(M\) is quasi-coherent (\(\mathrm{IsQuasicoherent}\,M\)).
