3217	\begin{lemma}[Localization is flat]
3218	  \label{lem:isLocalization_flat_mathlib}
3219	  \lean{IsLocalization.flat}
3220	  \mathlibok
3221	  \textit{Provided by Mathlib (\texttt{Mathlib.RingTheory.Flat.Localization}).}
3222	  If \(S\) is a localization of a commutative ring \(R\) at a multiplicative submonoid, then \(S\) is
3223	  a flat \(R\)-module. Consequently localization is exact and commutes with finite limits; this is
3224	  what lets the section-localization functor pass through the finite sheaf equalizer in the descent
3225	  (\cref{lem:section_localization_descent}).
3226	\end{lemma}
